import UIKit
import WebKit

class ViewController: UIViewController {
    private var userContentController: WKUserScript {
        let injectionCode = """
            window.webkit.messageHandlers.iosHandler.postMessage(JSON.stringify({name:'init', value:''}));
            
            document.addEventListener('deviceready', function () {
                webkit.messagehandlers.ioshandler.postMessage(JSON.stringify({name:'deviceready', value:''}));
            });
        """
        
        return WKUserScript(source: injectionCode, injectionTime: .atDocumentStart)
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        let webView = WKWebView(frame: view.bounds)
        webView.navigationDelegate = self
        view.addSubview(webView)
        
        let request = URLRequest(url: URL(string:"your-website-URL")!)
        webView.load(request)
        
        // Configure the UserScript
        webView.configuration.userContentController.addUserScript(userContentCode)
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        print("Message from WebView: \(message.name), data: \(String(describing: message.body))")
        
        if message.name == "requestCameraAccess" {
            // Call the native function to request camera access
            let photoLibrary = PHPhotoLibrary.shared()
            photoLibrary.requestAuthorization { status in
                switch status {
                case .authorized:
                    print("Camera permission granted")
                case .denied:
                    print("Camera permission denied")
                default:
                    print("Camera permission not determined")
                }
            }
        } else if message.name == "showNotification" {
            // Call the native function to show a notification
            let userInfo = ["title":message.body,"text":"This is some text","soundName":"default"]
            let notification = UNMutableNotificationContent(userInfo: userInfo as [String : Any])
            
            let trigger = UNTimeIntervalNotificationTrigger(timeInterval: 1, repeats: false)
            
            let request = UNPushNotificationRequest(identifier: "your-notification-id", content: notification, trigger: trigger)
            
            let center = UNUserNotificationCenter.current()
            center.add(request) { (error) in
                if let error = error {
                    print("Failed to schedule notification: \(error.localizedDescription)")
                } else {
                    print("Successfully scheduled notification")
                }
            }
        }
    }
